-- +goose Up
-- The "Pair with a drink" feature (lib/core/providers/nutrition_provider.dart →
-- drinkFoodIds, lib/screens/food_detail.dart → drinkMacros) logs a second meal
-- item that points at these 12 helper drink foods. They had been created
-- out-of-band with no nutrient rows, so they rendered as empty "duplicates" of
-- the VitaminFinder drink catalog (…8003-0000002xx) in the admin food list and
-- contributed nothing to daily totals. Seed/repair them here so they live in
-- version control, carry a distinct source, and hold the same per-100 ml macros
-- the client uses for its pre-log estimate.

INSERT INTO foods (id, name, category, serving_size_g, source, verified) VALUES
